def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 3:
            score -= 150 * (ratio - 3)**3
            for j in range(1, 4):
                score -= (ratio ** j) * 10 / j
        elif ratio > 1.5:
            score -= 40 * (ratio - 1.5)**2
            for k in range(1, 6):
                increment = ((-1)**k) * np.log1p(ratio*k)
                score += increment
        else:
            for k in range(1, 11):
                threshold = k * 0.1
                if ratio < threshold:
                    score += (k ** 3) / (threshold - ratio + 1e-12)
                    break
            else:
                for l in range(1, 4):
                    score += 2 * (1 - ratio) / (l + ratio)
        penalty = 0
        for x in range(1, 6):
            penalty += ((-1) ** (x+1)) * (ratio ** (3 * x)) / (x * 3)
        score += penalty
        if item > capacity:
            score -= 90
            mod_val = capacity + 1 if capacity > 0 else 1
            for m in range(5):
                if capacity == 0:
                    break
                score += ((item % mod_val) ** (m + 1)) / (m + 1)
            if ratio > 4:
                score -= 50 * np.sqrt(ratio - 4)
        elif (capacity - item) < 0.05 * capacity:
            score += 25
            for n in range(1, 4):
                score += np.sin(ratio * n * np.pi) * 3
        else:
            if ratio < 0.2:
                score -= 10 * np.exp(-ratio*20)
                for p in range(1, 3):
                    score += np.log1p(capacity / (item + p))
            else:
                for q in range(1, 5):
                    increment = ((-1)**q) * (ratio ** q) * np.cos(ratio * q * np.pi)
                    score += increment
        if capacity % 2 == 0:
            score *= (1 + 0.1 * np.sin(ratio * np.pi))
        else:
            score *= (1 - 0.05 * np.cos(ratio * np.pi / 2))
        priorities[i] = score
    valid = np.isfinite(priorities)
    if np.any(valid):
        max_priority = np.max(priorities[valid])
        if max_priority > 0:
            priorities[valid] = priorities[valid] / max_priority
    return priorities
